"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[2777],{8310:e=>{e.exports=JSON.parse('{"lang":"fr","resources":{"landing":{"meta":{"title":"Linguist \u2013 Extension de traduction ax\xe9e sur la confidentialit\xe9 pour Chrome et Firefox","description":"Extension de navigateur pour traduire des pages web, du texte s\xe9lectionn\xe9 et des sous-titres. Fonctionne instantan\xe9ment et propose une traduction hors ligne."},"navigation":{"features":{"content":"Fonctionnalit\xe9s"},"blog":{"content":"Blog"},"docs":{"content":"Documentation"},"github":{"content":"GitHub"}},"install":{"chrome":"Installer pour Chrome","firefox":"Installer pour Firefox"},"sections":{"hero":{"title":"Traduisez n\'importe quel contenu dans votre navigateur","description":"Linguist est une extension de navigateur qui traduit le texte instantan\xe9ment.\\n\\nElle vous permet de traduire des pages web compl\xe8tes, du texte s\xe9lectionn\xe9, des sous-titres Netflix et des messages priv\xe9s. Vous pouvez \xe9couter le texte traduit et enregistrer les traductions importantes dans votre dictionnaire personnel pour apprendre de nouveaux mots, m\xeame hors ligne.\\n\\nLinguist est une alternative moderne et respectueuse de la vie priv\xe9e aux extensions comme Google Traduction. Essayez-la gratuitement."},"opensource":{"title":"Open source","content":"Linguist est une extension de traduction gratuite et <0>open source</0>. Elle ne collecte ni ne vend les donn\xe9es des utilisateurs.\\n\\nVous pouvez <1>faire un don</1> pour soutenir Linguist et nous aider \xe0 maintenir notre ind\xe9pendance et un niveau de qualit\xe9 \xe9lev\xe9.\\n\\nPartagez Linguist sur les r\xe9seaux sociaux pour aider d\'autres personnes \xe0 la d\xe9couvrir."},"support":{"title":"Assistance","content":"Si vous avez des questions, contactez-nous <0/>.\\nSi vous avez trouv\xe9 un bug et poss\xe9dez un compte GitHub, veuillez <1>ouvrir un ticket</1>."},"createdBy":{"content":"Cr\xe9\xe9 par <0/>."}},"features":{"title":"Fonctionnalit\xe9s","items":{"offlineTranslation":{"title":"Traduction hors ligne et confidentialit\xe9","content":"Le traducteur hors ligne int\xe9gr\xe9 permet de traduire du texte directement sur votre appareil. Votre texte reste priv\xe9 et n\'est jamais envoy\xe9 sur Internet.\\n\\nEn activant cette fonctionnalit\xe9 dans les param\xe8tres, vous garantissez la confidentialit\xe9 de vos e-mails, documents ou messages personnels.\\n\\nCe mode hors ligne permet \xe9galement de traduire des pages web sans connexion, une option particuli\xe8rement pratique lors de vos d\xe9placements."},"fullPageTranslation":{"title":"Traduction de pages compl\xe8tes","content":"Une traduction rapide et de haute qualit\xe9 pour des pages enti\xe8res, en quelques clics seulement.\\n\\nUn simple raccourci clavier permet de traduire instantan\xe9ment. Il suffit de survoler le texte traduit pour afficher l\'original. Vous pouvez m\xeame traduire des pages priv\xe9es, accessibles apr\xe8s connexion ou derri\xe8re un acc\xe8s payant.\\n\\nDes r\xe8gles de traduction automatique peuvent \xeatre configur\xe9es selon la langue ou le domaine du site.\\n\\nLinguist adopte une approche respectueuse de la structure des pages : seul le texte est modifi\xe9, ce qui pr\xe9serve la mise en page et le confort de navigation.\\n\\nLa traduction en temps r\xe9el est \xe9galement disponible pour faciliter les r\xe9unions multilingues sur Zoom, Google Meet et Microsoft Teams."},"selectedTextTranslation":{"title":"Traduction de texte s\xe9lectionn\xe9","content":"Vous rencontrez des mots inconnus en lisant un article en ligne ?\\nIl vous suffit de s\xe9lectionner le texte sur la page et de cliquer sur le bouton de traduction.\\n\\nVous pouvez \xe9couter le texte original et sa traduction, puis enregistrer les termes dans votre dictionnaire pour les r\xe9viser plus tard."},"textTranslation":{"title":"Traduction rapide de texte","content":"Besoin de traduire quelque chose rapidement ? Cliquez sur l\'ic\xf4ne Linguist et saisissez votre texte.\\n\\nPlus besoin de changer d\'onglet ou d\'ouvrir des sites de traduction. Traduisez directement dans votre navigateur en utilisant le service de votre choix."},"knowledgeBase":{"title":"Cr\xe9ation d\'une base de connaissances personnelle","content":"Chaque traduction est enregistr\xe9e dans votre historique, et vous pouvez ajouter les termes importants \xe0 votre dictionnaire personnel. Vous pouvez effectuer des recherches dans votre dictionnaire et votre historique \xe0 tout moment.\\n\\nRien ne se perd, m\xeame lors de longues sessions de recherche ou d\'apprentissage.\\n\\nLe dictionnaire fonctionne hors ligne, ce qui rend Linguist id\xe9al pour l\'apprentissage des langues et pour les voyageurs qui ont besoin d\'un acc\xe8s constant \xe0 leur vocabulaire."},"customTranslators":{"title":"Traducteurs personnalis\xe9s","content":"Linguist vous laisse choisir le service de traduction \xe0 utiliser.\\n\\nL\'extension prend en charge les fournisseurs populaires tels que Google, Yandex et Microsoft, avec plus de 100 langues disponibles.\\n\\nSi le service dont vous avez besoin n\'est pas inclus, vous pouvez l\'ajouter en tant que <0>traducteur personnalis\xe9</0>.\\n\\nCes traducteurs personnalis\xe9s permettent d\'int\xe9grer n\'importe quel syst\xe8me de traduction, qu\'il s\'agisse de services bas\xe9s sur l\'IA comme ChatGPT, DeepL, DeepSeek et Gemini, ou de traducteurs locaux fonctionnant directement sur votre appareil, comme Ollama ou LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"Qu\'est-ce que Linguist ?","content":"Linguist est une extension de traduction pour Chrome et Firefox, con\xe7ue pour prot\xe9ger votre vie priv\xe9e.\\n\\nElle permet de traduire des pages web compl\xe8tes, du texte s\xe9lectionn\xe9, des sous-titres et des messages directement dans votre navigateur, sans avoir \xe0 ouvrir des sites de traduction externes."},"whyLinguist":{"title":"Pourquoi utiliser Linguist ?","content":"Il existe de nombreuses extensions pour traduire des pages web, et certains navigateurs int\xe8grent m\xeame leur propre traducteur. Alors, pourquoi choisir Linguist ?\\n\\nLa plupart des traducteurs int\xe9gr\xe9s et des extensions manquent de flexibilit\xe9. Beaucoup d\xe9pendent d\'un seul fournisseur comme Google Traduction ou Microsoft Bing, tandis que Firefox propose son propre traducteur hors ligne. Bien souvent, il est impossible de choisir le service qui correspond le mieux \xe0 vos besoins.\\n\\nSi la qualit\xe9 de traduction ne vous convient pas, ou si vous refusez d\'envoyer des textes priv\xe9s \xe0 des services tiers, la plupart des outils n\'offrent aucune alternative satisfaisante.\\n\\nDe plus, de nombreux outils se limitent \xe0 une seule t\xe2che : certains traduisent des pages enti\xe8res, d\'autres uniquement du texte s\xe9lectionn\xe9.\\n\\nParall\xe8lement, certaines extensions sont principalement con\xe7ues pour \xeatre mon\xe9tis\xe9es. Des fonctionnalit\xe9s comme l\'historique de traduction ou les dictionnaires personnels n\xe9cessitent parfois un abonnement, et m\xeame des options de base comme le mode sombre sont parfois payantes.\\n\\nLinguist adopte une approche diff\xe9rente. C\'est un outil de traduction pens\xe9 pour \xeatre pratique. Vous pouvez choisir le service de traduction qui vous convient le mieux, passer d\'un fournisseur \xe0 l\'autre, ou ajouter vos propres traducteurs personnalis\xe9s.\\n\\nLinguist r\xe9unit \xe9galement tout au m\xeame endroit : la traduction de pages web enti\xe8res, de texte s\xe9lectionn\xe9, de sous-titres et de messages, tout en conservant une trace des traductions importantes dans votre historique et votre dictionnaire personnel."},"theLinguistLogo":{"title":"Pourquoi le logo de Linguist est-il la tour de Babel ?","content":"Le logo de Linguist s\'inspire de la <wiki>tour de Babel</wiki>, l\'une des plus anciennes histoires sur le langage et la communication.\\n\\nSelon ce r\xe9cit, les humains parlaient autrefois une seule et m\xeame langue et ont entrepris de construire une tour atteignant le ciel. La tour n\'a jamais \xe9t\xe9 achev\xe9e, et l\'humanit\xe9 s\'est dispers\xe9e \xe0 travers de multiples langues. Depuis lors, les diff\xe9rences linguistiques ont souvent compliqu\xe9 la communication.\\n\\nLinguist a \xe9t\xe9 cr\xe9\xe9 pour aider \xe0 surmonter cet obstacle.\\n\\nLa tour de Babel pr\xe9sente sur le logo rappelle cette histoire : une multitude de langues, de cultures, et l\'effort constant des \xeatres humains pour se comprendre. Linguist contribue \xe0 rapprocher les personnes en rendant la traduction simple, flexible et accessible directement dans le navigateur.\\n\\nCe logo refl\xe8te \xe9galement l\'esprit du projet. Linguist n\'est pas une simple interface de plus pour \xab Google Traduction \xbb. C\'est un outil con\xe7u par des personnes passionn\xe9es par les langues, la protection de la vie priv\xe9e et les technologies ouvertes. La tour de Babel symbolise la curiosit\xe9, l\'apprentissage et l\'id\xe9e que les diff\xe9rences linguistiques doivent rassembler les gens plut\xf4t que de les diviser."},"imageTranslation":{"title":"Pourquoi Linguist ne traduit-il pas le texte des images ?","content":"Linguist se concentre sur des fonctionnalit\xe9s de traduction fiables et de haute qualit\xe9.\\n\\nNous avons \xe9tudi\xe9 diff\xe9rentes approches pour traduire le texte contenu dans les images. Actuellement, la plupart des solutions disponibles n\'offrent pas de r\xe9sultats constants, en particulier lorsqu\'elles s\'ex\xe9cutent directement dans le navigateur, ce qui est pourtant essentiel pour garantir la confidentialit\xe9 des utilisateurs.\\n\\nC\'est pourquoi Linguist n\'int\xe8gre pas la traduction d\'images pour le moment. Nous pr\xe9f\xe9rons ne pas proposer de fonctionnalit\xe9s qui ne r\xe9pondent pas \xe0 nos crit\xe8res de qualit\xe9.\\n\\nSi nous trouvons \xe0 l\'avenir une m\xe9thode fiable et respectueuse de la vie priv\xe9e pour traduire les images, nous serons ravis de l\'ajouter."},"howTranslatePages":{"title":"Comment Linguist traduit-il les pages web ?","content":"Linguist permet de traduire des pages web enti\xe8res en quelques clics. Vous pouvez lancer la traduction d\'une page \xe0 l\'aide du bouton de l\'extension ou d\'un raccourci clavier.\\n\\nLe texte original reste toujours accessible. Il suffit de survoler le texte traduit pour l\'afficher."},"offlineTranslation":{"title":"Linguist peut-il traduire des pages hors ligne ?","content":"Oui. Linguist int\xe8gre un traducteur hors ligne qui permet de traduire du texte sans envoyer de donn\xe9es sur Internet.\\n\\nCela garantit la protection de votre vie priv\xe9e et vous permet de traduire du contenu m\xeame sans connexion Internet."},"privacy":{"title":"Linguist respecte-t-il la vie priv\xe9e ?","content":"Oui. Linguist a \xe9t\xe9 con\xe7u en pla\xe7ant la confidentialit\xe9 au c\u0153ur de ses priorit\xe9s.\\n\\nL\'extension ne collecte ni ne vend les donn\xe9es des utilisateurs. Lorsque vous utilisez le <offline-translator>traducteur hors ligne</offline-translator>, les traductions sont trait\xe9es int\xe9gralement sur votre appareil."},"supportedBrowsers":{"title":"Quels navigateurs sont compatibles avec Linguist ?","content":"Linguist est disponible pour Chrome et Firefox. L\'extension fonctionne \xe9galement sur d\'autres navigateurs bas\xe9s sur Chromium qui prennent en charge les extensions Chrome.\\n\\nLinguist est aussi compatible avec les navigateurs Android prenant en charge les extensions, comme Firefox pour Android et certains navigateurs bas\xe9s sur Chromium."},"selectedText":{"title":"Linguist peut-il traduire du texte s\xe9lectionn\xe9 ?","content":"Oui. Il suffit de s\xe9lectionner du texte sur n\'importe quelle page web et d\'utiliser le bouton de traduction pour le traduire instantan\xe9ment.\\n\\nVous pouvez \xe9galement \xe9couter la traduction et l\'enregistrer dans votre dictionnaire personnel."},"customTranslators":{"title":"Puis-je utiliser mon propre service de traduction ?","content":"Oui. Linguist prend en charge les <custom-translator>traducteurs personnalis\xe9s</custom-translator>, ce qui vous permet d\'int\xe9grer des services de traduction suppl\xe9mentaires.\\n\\nVous pouvez connecter des API externes ou des syst\xe8mes de traduction locaux tels que <libre-translate>LibreTranslate</libre-translate> ou <ollama>Ollama</ollama>."},"isFree":{"title":"Linguist est-il gratuit ?","content":"Oui. Linguist est enti\xe8rement gratuit et <linguist>open source</linguist>.\\n\\nLe projet est soutenu par la communaut\xe9, et vous avez la possibilit\xe9 de <donations>le soutenir en faisant un don</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pt","langName":"portugu\xeas","url":"https://linguister.io/pt"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh","langName":"\u4e2d\u6587","url":"https://linguister.io/zh"}]}')}}]);